void memCopy(void *dest, void *src, const size_t sx, const size_t sy) {
    cudaError_t errNum = cudaMemcpy(dest, src, sx * sy * sizeof(int), cudaMemcpyDeviceToDevice);
    if (errNum != cudaSuccess) fatal_CUDA(errNum, __LINE__);
}

void fdwt53(void *in, void *out, int sizeX, int sizeY, int levels) {
    if (sizeX >= 960) {
        launchFDWT53Kernel(192, 8, in, out, sizeX, sizeY);
    } else if (sizeX >= 480) {
        launchFDWT53Kernel(128, 8, in, out, sizeX, sizeY);
    } else {
        launchFDWT53Kernel(64, 8, in, out, sizeX, sizeY);
    }

    if (levels > 1) {
        const int llSizeX = (sizeX / 2) + ((sizeX % 2) ? 1 : 0);
        const int llSizeY = (sizeY / 2) + ((sizeY % 2) ? 1 : 0);
        memCopy(in, out, llSizeX, llSizeY);

        fdwt53(in, out, llSizeX, llSizeY, levels - 1);
    }
}

