            dim3 globalWorkSize(gx * 64, gy * 1, 1);
            dim3 localWorkSize(64, 1, 1);
            cl_fdwt53Kernel<<<globalWorkSize, localWorkSize>>>(in, out, sizeX, sizeY, steps, 64, 8);
        }

        if (levels > 1) {
            const int llSizeX = (sizeX / 2) + ((sizeX % 2) ? 1 : 0);
            const int llSizeY = (sizeY / 2) + ((sizeY % 2) ? 1 : 0);
            cudaMemcpy(in, out, llSizeX * llSizeY * sizeof(int), cudaMemcpyDeviceToDevice);
            fdwt53(in, out, llSizeX, llSizeY, levels - 1);
        }
    }
}
